.card-certeza-label {
  line-height: 1;
}

/* ---- Image placeholder ---- */

.card-image-placeholder {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: var(--color-sepia-light);
  display: flex;
  align-items: center;
  justify-content: center;
  border-top: 1px solid var(--color-card-border);
  border-bottom: 1px solid var(--color-card-border);
  overflow: hidden;
}

.card-image-placeholder__text {
  font-family: var(--font-body);
  font-size: 0.75rem;
  font-weight: 400;
  color: var(--color-text-muted);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  opacity: 0.6;
}

/* ---- Card images (real historical images) ---- */

.card-image {
  width: 100%;
  max-height: 220px;
  overflow: hidden;
  border-top: 1px solid var(--color-card-border);
  border-bottom: 1px solid var(--color-card-border);
  background-color: var(--color-sepia-light);
  position: relative;
}

.card-image img {
  width: 100%;
  height: 100%;
  max-height: 220px;
  object-fit: cover;
  display: block;
  transition: opacity var(--duration-normal) var(--ease-out);
}

/* Fallback for broken image loads */
.card-image img.img-error {
  opacity: 0;
}

.card-image.img-fallback::after {
  content: attr(data-fallback-text);
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-body);
  font-size: 0.75rem;
  font-weight: 400;
  color: var(--color-text-muted);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  opacity: 0.6;
  background-color: var(--color-sepia-light);
  text-align: center;
  padding: var(--space-md);
}

/* ---- Card inner content spacing ---- */

.card-hecho .event-card__year,
.card-opinion .event-card__year,
.card-rumor .event-card__year {
  margin: var(--space-lg) var(--space-lg) var(--space-sm);
}

